#include <stdio.h>
#include <time.h>
#include <assert.h>
#include <stdlib.h> 
#include <math.h> 
#include <sys/time.h>
#include <string.h>

#define STR_SIZE (256)
#define MAX_PD	(3.0e6)

#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP	0.5



float t_chip = 0.0005;
float chip_height = 0.016; float chip_width = 0.016; 

float amb_temp = 80.0;

void fatal(char *s)
{
    fprintf(stderr, "Error: %s\n", s);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 )
      fatal( "The file was not opened" );


    for (i=0; grid_rows-1 >= i; i++) 
      for (j=0; grid_cols-1 >= j; j++)
        for (k=0; layers-1 >= k; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
              fatal("not enough lines in file");
            if ((sscanf(str, "%f", &val) != 1))
              fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }

    fclose(fp);	

}


void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {

    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
      printf( "The file was not opened\n" );

    for (i=0; grid_rows > i; i++) 
      for (j=0; grid_cols > j; j++)
        for (k=0; layers > k; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }

    fclose(fp);	
}

__global__ void computeTempKernel(const float *pIn, const float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float cc, float cw, float ce, float cs, float cn, float cb, float ct, float amb_temp)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int size = nx * ny * nz;
    if (idx >= size) return;

    int x = idx % nx;
    int y = (idx / nx) % ny;
    int z = idx / (nx * ny);

    int c = idx;
    int w = (0 == x) ? c : c - 1;
    int e = (nx - 1 == x) ? c : c + 1;
    int n = (0 == y) ? c : c - nx;
    int s = (ny - 1 == y) ? c : c + nx;
    int b = (0 == z) ? c : c - nx * ny;
    int t = (nz - 1 == z) ? c : c + nx * ny;

    tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
        + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t] + (dt / Cap) * pIn[c] + ct * amb_temp;
}

void computeTempCUDA(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{
    float ce, cw, cn, cs, ct, cb, cc;

    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int size = nx * ny * nz;

    float *d_pIn, *d_tIn, *d_tOut;
    cudaMalloc((void**)&d_pIn, size * sizeof(float));
    cudaMalloc((void**)&d_tIn, size * sizeof(float));
    cudaMalloc((void**)&d_tOut, size * sizeof(float));

    cudaMemcpy(d_pIn, pIn, size * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_tIn, tIn, size * sizeof(float), cudaMemcpyHostToDevice);

    int threadsPerBlock = 256;
    int blocksPerGrid = (size + threadsPerBlock - 1) / threadsPerBlock;

    for (int iter = 0; iter < numiter; iter++) {
        computeTempKernel<<<blocksPerGrid, threadsPerBlock>>>(d_pIn, d_tIn, d_tOut, nx, ny, nz, Cap, Rx, Ry, Rz, dt, cc, cw, ce, cs, cn, cb, ct, amb_temp);
        cudaDeviceSynchronize();
        float *tmp = d_tIn;
        d_tIn = d_tOut;
        d_tOut = tmp;
    }

    // After last iteration, if numiter is odd, d_tIn points to output, else d_tOut
    if (numiter % 2 == 1) {
        cudaMemcpy(tOut, d_tIn, size * sizeof(float), cudaMemcpyDeviceToHost);
    } else {
        cudaMemcpy(tOut, d_tOut, size * sizeof(float), cudaMemcpyDeviceToHost);
    }

    cudaFree(d_pIn);
    cudaFree(d_tIn);
    cudaFree(d_tOut);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; len > i; i++)
    {
        err = err + ((arr1[i]-arr2[i]) * (arr1[i]-arr2[i]));
    }

    return (float)sqrt(err/len);


}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{   float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; nz > z; z++)
            for(y = 0; ny > y; y++)
                for(x = 0; nx > x; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (0 == x) ? c      : c - 1;
                    e = (nx - 1 == x) ? c : c + 1;
                    n = (0 == y) ? c      : c - nx;
                    s = (ny - 1 == y) ? c : c + nx;
                    b = (0 == z) ? c      : c - nx * ny;
                    t = (nz - 1 == z) ? c : c + nx * ny;


                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(numiter > i);

}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows/cols> <layers> <iterations> <powerFile> <tempFile> <outputFile>\n", argv[0]);
    fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
    fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");

    fprintf(stderr, "\t<iteration> - number of iterations\n");
    fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
    fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<outputFile - output file\n");
    exit(1);
}



int main(int argc, char** argv)
{
    if (7 != argc)
    {
        usage(argc,argv);
    }

    char *pfile, *tfile, *ofile;
    int iterations = atoi(argv[3]);

    pfile = argv[4];
    tfile = argv[5];
    ofile = argv[6];

    int numCols = atoi(argv[1]);
    int numRows = atoi(argv[1]);
    int layers = atoi(argv[2]);



    float dx = chip_height/numRows;
    float dy = chip_width/numCols;
    float dz = t_chip/layers;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx = dy / (2.0 * K_SI * t_chip * dx);
    float Ry = dx / (2.0 * K_SI * t_chip * dy);
    float Rz = dz / (K_SI * dx * dy);


    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt = PRECISION / max_slope;


    float *powerIn, *tempOut, *tempIn, *tempCopy;

    int size = numCols * numRows * layers;

    powerIn = (float*)calloc(size, sizeof(float));
    tempCopy = (float*)malloc(size * sizeof(float));
    tempIn = (float*)calloc(size,sizeof(float));
    tempOut = (float*)calloc(size, sizeof(float));

    float* answer = (float*)calloc(size, sizeof(float));


    readinput(powerIn,numRows, numCols, layers,pfile);
    readinput(tempIn, numRows, numCols, layers, tfile);

    memcpy(tempCopy,tempIn, size * sizeof(float));

    struct timeval start, stop;
    float time;
    gettimeofday(&start,NULL);
    computeTempCUDA(powerIn, tempIn, tempOut, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt,iterations);
    gettimeofday(&stop,NULL);
    time = (stop.tv_usec-start.tv_usec)*1.0e-6 + stop.tv_sec - start.tv_sec;
    computeTempCPU(powerIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt,iterations);

    float acc = accuracy(tempOut,answer,numRows*numCols*layers);
    printf("Time: %.3f (s)\n",time);
    printf("Accuracy: %e\n",acc);
    writeoutput(tempOut,numRows, numCols, layers, ofile);
    free(tempIn);
    free(tempOut); free(powerIn);
    free(tempCopy);
    free(answer);
    return 0;
}
